import { Component } from '@angular/core';

@Component({
  selector: 'app-acceso-denegado',
  templateUrl: './acceso-denegado.component.html'
})
export class AccesoDenegadoComponent {
}
<div class="container text-center mt-5">
  <h1 class="display-1 text-danger">403</h1>
  <h2>Acceso Denegado</h2>
  <p class="lead">No tienes los permisos necesarios para ver esta página.</p>
  <p>Tu sesión sigue activa, pero este recurso es exclusivo para otro rol.</p>
  <button class="btn btn-primary mt-3" routerLink="/canchas">Volver a Canchas</button>
</div>
